// Générer ref_bien avec UUID pour éviter collisions
// Format: TypeCode-CommuneCode-RandomUUID

const cleanText = (s) => s?.toLowerCase?.().replace(/[^a-z0-9]/g, '') || '';

const typeMapping = {
  'appartement': 'A', 'studio': 'S', 'chambre': 'C', 'maison': 'M', 'villa': 'V',
  'duplex': 'D', 'terrain': 'T', 'bureau': 'B', 'magasin': 'G', 'local': 'L'
};

const type = $json.type_de_bien ? ($json.type_de_bien.toLowerCase().substring(0, 3)) : 'XXX';
const typeCode = typeMapping[type] || type.substring(0, 1).toUpperCase();

const commune = $json.commune ? $json.commune.substring(0, 3).toUpperCase() : 'XXX';

// OPTION 1: UUID v4 aléatoire (recommandé)
const uuid = 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function(c) {
  var r = Math.random() * 16 | 0, v = c === 'x' ? r : (r & 0x3 | 0x8);
  return v.toString(16);
});
const shortUuid = uuid.substring(0, 8).toUpperCase();

const ref_bien = `${typeCode}-${commune}-${shortUuid}`;

console.log('✅ ref_bien généré: ' + ref_bien);
console.log('   Type: ' + typeCode + ', Commune: ' + commune + ', UUID: ' + shortUuid);

// Vérifier les doublons (dernière 50 annonces seulement)
let annonces = [];
try {
  annonces = $('Charger Annonces Recentes').first().json || [];
} catch(e) {
  console.log('⚠️  Charger Annonces échoué, pas de vérif doublons');
}

// Vérifier le contenu_hash pour détecter les vrais doublons
const contentHash = require('crypto')
  .createHash('md5')
  .update(JSON.stringify({
    type: $json.type_de_bien,
    prix: $json.prix,
    commune: $json.commune,
    quartier: $json.quartier,
    caracteristiques: $json.caracteristiques
  }))
  .digest('hex');

const isDuplicate = annonces.some(a => a.content_hash === contentHash);

if (isDuplicate) {
  console.log('🔄 Doublon détecté (contenu identique)');
  return [];
}

return [{
  json: {
    ...($json),
    ref_bien: ref_bien,
    content_hash: contentHash
  }
}];

const source = $input.first().json;
const text = source.text || source.messageBody || '';
if (!text || !text.trim()) return [];
return [{ json: { text: text.trim() } }];

const normalized = $('Normaliser Webhook').first().json;
let messageBody = normalized.messageBody || '';
if (!messageBody) messageBody = normalized.message?.conversation || '';
if (!messageBody) messageBody = normalized.message?.extendedTextMessage?.text || '';
if (!messageBody.trim()) { return [{ json: { text: '[Message vide reçu]', _debug_no_text: true, _raw_keys: Object.keys(normalized) } }]; }
return [{ json: { text: messageBody.trim() } }];

// Outil de recherche - Messages honnêtes uniquement
// Jamais d'erreur technique, juste "Je n'ai rien" ou résultats

const searchInput = $fromAI('search_term', 'Ex: villa, Cocody, meublé', 'string');

if (!searchInput || !searchInput.trim()) {
  return '{"resultats": [], "nombre": 0, "message": "Pas de terme."}';
}

const input = searchInput.trim();

function parseSearchPhrase(phrase) {
  const communes = ['cocody', 'yopougon', 'marcory', 'koumassi', 'treichville', 'plateau', 'adjame', 'abobo', 'attecoube', 'port-bouet', 'bingerville', 'songon', 'anyama', 'bassam', 'assinie'];
  const types = ['appartement', 'studio', 'chambre', 'maison', 'villa', 'duplex', 'triplex', 'terrain', 'bureau', 'magasin', 'boutique', 'entrepot', 'immeuble', 'local', 'residence', 'parking', 'garage'];
  const quartiers = ['angre', 'riviera', 'plateau', 'cocody centre', 'la sobrerie', 'deux plateaux', 'bapro', 'calavi'];
  const caracteristiques = ['meuble', 'meublé', 'climatise', 'climatisé', 'neuf', 'renovate', 'renové', 'securise', 'sécurisé'];

  const words = phrase.toLowerCase().split(/[\s,;]+/).filter(w => w.length > 0);
  const found = { communes: [], types: [], quartiers: [], caracteristiques: [], other: [] };

  for (const word of words) {
    if (communes.some(c => word.includes(c) || c.includes(word))) {
      const comm = communes.find(c => word.includes(c) || c.includes(word));
      if (!found.communes.includes(comm)) found.communes.push(comm);
    } else if (types.some(t => word.includes(t) || t.includes(word))) {
      const type = types.find(t => word.includes(t) || t.includes(word));
      if (!found.types.includes(type)) found.types.push(type);
    } else if (quartiers.some(q => word.includes(q) || q.includes(word))) {
      const qu = quartiers.find(q => word.includes(q) || q.includes(word));
      if (!found.quartiers.includes(qu)) found.quartiers.push(qu);
    } else if (caracteristiques.some(c => word.includes(c) || c.includes(word))) {
      const car = caracteristiques.find(c => word.includes(c) || c.includes(word));
      if (!found.caracteristiques.includes(car)) found.caracteristiques.push(car);
    } else if (word.length > 2) {
      found.other.push(word);
    }
  }

  return found;
}

const parsed = parseSearchPhrase(input);

const filters = [];

for (const commune of parsed.communes) {
  const encoded = encodeURIComponent('*' + commune + '*');
  filters.push('commune.ilike.' + encoded);
}

for (const type of parsed.types) {
