  filters.push(
    'type_de_bien.ilike.' + encoded,
    'commune.ilike.' + encoded,
    'quartier.ilike.' + encoded,
    'caracteristiques.ilike.' + encoded,
    'ref_bien.ilike.' + encoded,
    'zone_geographique.ilike.' + encoded
  );
}

const selectFields = 'ref_bien,type_de_bien,type_offre,commune,quartier,prix,caracteristiques,meubles,chambre,zone_geographique,lien_image';
const filterString = filters.join(',');
const path = '/rest/v1/locaux?disponible=eq.Oui&or=(' + filterString + ')&select=' + selectFields + '&limit=10';

const apiKey = 'eyJhbGciOiJIUzI1NiIsInR5cCI6IkpXVCJ9.eyJpc3MiOiJzdXBhYmFzZSIsInJlZiI6InVkeWZoenl2YWxhbnNtaGt5bm5jIiwicm9sZSI6InNlcnZpY2Vfcm9sZSIsImlhdCI6MTc3MTE5NjM1NywiZXhwIjoyMDg2NzcyMzU3fQ.XToUDvcD-crlO0bA8HuJ5g1GjhqTl790fHG6H8bujAk';

return new Promise((resolve) => {
  const https = require('https');

  const options = {
    hostname: 'udyfhzyvalansmhkynnc.supabase.co',
    path: path,
    method: 'GET',
    headers: {
      'apikey': apiKey,
      'Authorization': 'Bearer ' + apiKey,
      'Content-Type': 'application/json'
    },
    timeout: 10000
  };

  const req = https.request(options, (res) => {
    let body = '';
    res.on('data', (chunk) => { body += chunk; });
    res.on('end', () => {
      try {
        const data = JSON.parse(body);

        if (!Array.isArray(data) || data.length === 0) {
          resolve(JSON.stringify({
            resultats: [],
            nombre: 0,
            message: 'Je n\'ai rien trouvé qui correspond.'
          }));
