        }));
      } catch (e) {
        resolve(JSON.stringify({
          resultats: [],
          nombre: 0,
          message: 'Je n\'ai rien trouvé pour le moment.'
        }));
      }
    });
  });

  req.on('error', () => {
    resolve(JSON.stringify({
      resultats: [],
      nombre: 0,
      message: 'Je n\'ai rien qui correspond en ce moment.'
    }));
  });

  req.on('timeout', () => {
    req.destroy();
    resolve(JSON.stringify({
      resultats: [],
      nombre: 0,
      message: 'Je n\'ai rien pour l\'instant.'
    }));
  });

